import argparse
import json
import os
import sys
from collections import defaultdict
from datetime import datetime
from pathlib import Path

METRIC_PAIRS = {
    "claude": ("5h sessions (all models)", "Weekly (all models)"),
    "codex": ("Session (5h)", "Weekly (7d)"),
}


def parse_ts(ts: str) -> datetime:
